                                <C>
                            }

                            class ScanSecHubReport {
                                <C>
                            }

                            class ScanReportRepository {
                                <C>
                            }
                        }

                        commons #E8FFF5 {
                            model #FFFFFF {
                                enum Severity {
                                    LOW
                                    MEDIUM
                                    HIGH
                                }

                                enum ScanType {
                                    CODE_SCAN
                                    WEB_SCAN
                                }

                                class SecHubFinding {
                                    <C>
                                }

                                class SecHubCodeCallStack {
                                    <C>
                                }
                            }
                        }
                    }

                    ' Relationships within Project Package

                    FalsePositiveJobDataService --> ScanProjectConfigService
                    FalsePositiveJobDataService ..|> FalsePositiveJobDataListValidation
                    FalsePositiveJobDataService o--* FalsePositiveJobDataConfigMerger

                    ScanProjectConfigService --o ScanProjectConfigRepository
                    ScanProjectConfigRepository .u. ScanProjectConfig

                    FalsePositiveJobDataConfigMerger u- d-> FalsePositiveEntry
